package main; import ("encoding/json"; "fmt"; "log"; "net/http"; "sync"; "time"; "github.com/gorilla/websocket"); type Server struct { tasks map[string]Task; clients map[*websocket.Conn]bool; nextID int; mu sync.RWMutex }; type Task struct { ID string `json:"id"`; Title string `json:"title"`; Status string `json:"status"`; Priority int `json:"priority"`; CreatedAt time.Time `json:"created_at"`; UpdatedAt time.Time `json:"updated_at"`; CompletedAt *time.Time `json:"completed_at,omitempty"` }; type TaskUpdate struct { ID string `json:"id"`; Status string `json:"status"` }; var upgrader = websocket.Upgrader{CheckOrigin: func(r *http.Request) bool { return true }}; func main() { server := &Server{tasks: make(map[string]Task), clients: make(map[*websocket.Conn]bool)}; http.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) { json.NewEncoder(w).Encode(map[string]string{"status": "healthy"}) }); http.HandleFunc("/tasks", func(w http.ResponseWriter, r *http.Request) { switch r.Method { case http.MethodGet: server.mu.RLock(); json.NewEncoder(w).Encode(server.tasks); server.mu.RUnlock(); case http.MethodPost: var task Task; if err := json.NewDecoder(r.Body).Decode(&task); err != nil { http.Error(w, err.Error(), http.StatusBadRequest); return }; server.mu.Lock(); server.nextID++; task.ID = fmt.Sprintf("task_%d", server.nextID); task.CreatedAt = time.Now(); task.UpdatedAt = time.Now(); task.Status = "pending"; server.tasks[task.ID] = task; server.mu.Unlock(); json.NewEncoder(w).Encode(task); server.broadcast(task); default: http.Error(w, "method not allowed", http.StatusMethodNotAllowed) } }); http.HandleFunc("/tasks/update", func(w http.ResponseWriter, r *http.Request) { if r.Method != http.MethodPost { http.Error(w, "method not allowed", http.StatusMethodNotAllowed); return }; var update TaskUpdate; if err := json.NewDecoder(r.Body).Decode(&update); err != nil { http.Error(w, err.Error(), http.StatusBadRequest); return }; server.mu.Lock(); if task, exists := server.tasks[update.ID]; exists { task.Status = update.Status; task.UpdatedAt = time.Now(); if update.Status == "completed" { now := time.Now(); task.CompletedAt = &now }; server.tasks[update.ID] = task; json.NewEncoder(w).Encode(task); server.broadcast(task) } else { http.Error(w, "task not found", http.StatusNotFound) }; server.mu.Unlock() }); http.HandleFunc("/ws", func(w http.ResponseWriter, r *http.Request) { conn, _ := upgrader.Upgrade(w, r, nil); server.mu.Lock(); server.clients[conn] = true; server.mu.Unlock(); defer func() { server.mu.Lock(); delete(server.clients, conn); server.mu.Unlock(); conn.Close() }(); for { _, _, err := conn.ReadMessage(); if err != nil { break } } }); log.Printf("Task Manager server starting on :8097"); log.Fatal(http.ListenAndServe(":8097", nil)) }; func (s *Server) broadcast(task Task) { s.mu.RLock(); for client := range s.clients { client.WriteJSON(task) }; s.mu.RUnlock() }
